715	/* Greek-key (meander) divider, SVG-based, can be applied to any hr or div.
716	   Renders as a repeating pattern across the full container width. */
717	.meander {
718	  height: 18px;
719	  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 36 18' preserveAspectRatio='xMinYMin slice'><path d='M0 4 L12 4 L12 14 L24 14 L24 4 L36 4' fill='none' stroke='%23a8762a' stroke-width='1' stroke-linecap='square' stroke-linejoin='miter'/></svg>");
720	  background-repeat: repeat-x;
721	  background-size: 36px 18px;
722	  border: 0;
723	  opacity: 0.7;
724	  margin: 1.5rem 0;
