727	/* Box-drawing-character ascii frame. Applied via:
728	     <div class="ascii-frame" data-label="CORNER TAG">...</div>
729	   The ::before and ::after render the corner characters at top-left and
730	   bottom-right; the data-label becomes a small label inset into the top
731	   border, like a UI panel from a 1980s terminal. */
732	.ascii-frame {
733	  position: relative;
734	  border: 1px solid var(--amber-dim);
735	  padding: 1.25rem 1.5rem;
736	  font-family: inherit;
737	  background: var(--stone-light);
738	  /* subtle inner glow as if the frame is lit from behind */
739	  box-shadow: inset 0 0 24px rgba(233, 163, 56, 0.03);
740	}
741	
742	.ascii-frame::before {
743	  content: '╔';
744	  position: absolute;
745	  top: -11px; left: -7px;
746	  color: var(--amber-dim);
747	  font-family: 'IBM Plex Mono', monospace;
748	  font-size: 1rem;
749	  background: var(--stone);
750	  padding: 0 2px;
751	  line-height: 1;
752	}
753	
754	.ascii-frame::after {
755	  content: '╝';
756	  position: absolute;
757	  bottom: -11px; right: -7px;
758	  color: var(--amber-dim);
759	  font-family: 'IBM Plex Mono', monospace;
760	  font-size: 1rem;
761	  background: var(--stone);
762	  padding: 0 2px;
763	  line-height: 1;
764	}
765	
766	.ascii-frame[data-label]::before {
767	  content: '╔═══ ' attr(data-label) ' ';
768	  padding: 0 6px 0 4px;
769	  letter-spacing: 0.1em;
770	  font-size: 0.7rem;
771	  color: var(--amber-dim);
