796	/* ── Page entrance animations ────────────────────────────────────────────── */
797	@keyframes fadeUp {
798	  from { opacity: 0; transform: translateY(8px); }
799	  to { opacity: 1; transform: translateY(0); }
800	}
801	
802	.fade-up { animation: fadeUp 0.4s ease forwards; }
803	
804	/* "Type in" flicker — content briefly flickers on first paint, like CRT
805	   phosphor warming up. Only runs on load; disabled by prefers-reduced-motion. */
806	@keyframes crt-flicker {
807	  0% { opacity: 0.6; }
808	  5% { opacity: 0.95; }
809	  10% { opacity: 0.7; }
810	  15% { opacity: 1; }
811	  100% { opacity: 1; }
812	}
813	
814	.crt-fade-in {
815	  animation: crt-flicker 0.9s ease-out forwards;
816	}
817	
818	@media (prefers-reduced-motion: reduce) {
819	  .crt-fade-in,
820	  .cursor::after,
821	  .fade-up,
822	  .gate-labyrinth,
823	  .gate-pulse,
824	  .crt-noise { animation: none !important; }
825	  /* Note: .gate-leave / .gate-hairline / .codex-arrival /
826	     .codex-arrival-hairline are also disabled by the later @media block
827	     at the end of this section. Listed here for discoverability. */
828	}
829	
830	/* ── Amber noise drift ──────────────────────────────────────────────────
831	 * The `<CRTOverlay />` amber-noise layer wallpapers a 256px tile across
832	 * the viewport and drifts the background-position very slowly (48s cycle
833	 * for 256px travel = ~5px/s). Slow enough to be subliminal; present enough
834	 * that the page feels alive rather than a flat render. */
835	.crt-noise {
836	  animation: crt-noise-drift 48s linear infinite;
837	}
838	
839	/* ── Light-mode CRT overlay dampening ─────────────────────────────────────
840	 *
841	 * The CRT noise + darkening vignette are the signature "amber oracle"
842	 * effect in dark mode. In light mode they'd fight the bright
843	 * parchment background instead: the noise layer is a dark amber
844	 * pattern at mix-blend-mode `screen` (designed for a black base) —
845	 * over parchment it just muddies the page. And the vignette
846	 * darkens the rim of a page that's supposed to read as ink-on-paper.
847	 *
848	 * Both get suppressed here. If a user ever wants the CRT feel back
849	 * they can flip `data-theme` to dark.
850	 */
851	[data-theme="light"] .crt-noise {
852	  display: none;
853	}
854	
855	[data-theme="light"] .crt-vignette {
856	  /* A whisper of darkening at the corners keeps the reading page
857	   * from feeling flat, without looking like an old monitor. */
858	  background: radial-gradient(
859	    ellipse at center,
860	    transparent 70%,
861	    rgba(90, 78, 58, 0.10) 100%
862	  ) !important;
863	}
864	
865	/* Dark mode is the default — explicit selector keeps the cascade
866	 * readable when we inspect in devtools. */
867	[data-theme="dark"] .crt-noise {
868	  display: block;
869	}
870	
871	@keyframes crt-noise-drift {
872	  0%   { background-position: 0 0; }
873	  100% { background-position: 256px 256px; }
874	}
875	
876	/* ── Gate (/) animations ─────────────────────────────────────────────────── */
877	
878	/* Idle state: the labyrinth rotates *slowly* (90s full turn) plus a subtle
879	   4s amber breath via drop-shadow intensity. The rotation is slow enough to
880	   feel like a ritual object, not a spinner. */
881	.gate-labyrinth {
882	  display: inline-block;
883	  animation: gate-spin-slow 90s linear infinite;
884	  color: var(--amber);
885	}
886	
887	.gate-pulse {
888	  animation: gate-spin-slow 90s linear infinite, gate-breath 4.5s ease-in-out infinite;
889	}
890	
891	/*
892	 * TRANSITION ANIMATION (login → dashboard) — minimalist rewrite
893	 * ─────────────────────────────────────────────────────────────
894	 * Two effects, no flash. Total ~300 ms:
895	 *
896	 *   1. `.gate-leave` on the form + wordmark + labyrinth:
897	 *        a 260 ms opacity + small translateY fade. The whole idle
898	 *        composition drifts down a hair and dims to zero. Ease-out so
899	 *        the motion settles rather than ending abruptly.
900	 *
901	 *   2. `.gate-hairline` (a thin amber line centred in the viewport via
902	 *      a flex wrapper in Gate.tsx):
903	 *        materialises at zero width, expands horizontally from the
904	 *        centre to full viewport width over ~180 ms, holds a beat,
905	 *        fades out. The sweep itself is the transition's only active
906	 *        visual element — no colour flashes, no screen fill.
907	 *
908	 * Both start together when `phase` flips to `entering`, run in parallel
909	 * for ~300 ms, and leave the viewport empty at the moment the router
910	 * navigates. The dashboard side (`.codex-arrival` +
911	 * `.codex-arrival-hairline`) mirrors the effect in reverse: the
912	 * hairline contracts back to centre while content fades up.
913	 *
914	 * Prior revision removed: a three-layer ignition with radial amber
915	 * shockwave (`.gate-flash`), rotating conic sunburst (`.gate-rays`),
916	 * and 9× scale / 1800° rotation on the hero (`.gate-open`). The
917	 * amber flash was visually loud and the most-complained-about detail.
918	 */
919	
920	@keyframes gate-spin-slow {
921	  from { transform: rotate(0deg); }
