19	async function latestCurrents(): Promise<PublicOpinion[]> {
20	  try {
21	    const response = await listCurrents(
22	      { limit: 3 },
23	      { next: { revalidate: 60, tags: ["public-home-currents"] } },
24	    );
25	    return Array.isArray(response.items) ? response.items.slice(0, 3) : [];
26	  } catch (error) {
27	    console.error("homepage_currents_preview_failed", error);
28	    return [];
29	  }
30	}
31	
32	async function latestArticles(): Promise<PublishedConclusion[]> {
33	  try {
34	    return await listPublishedArticles(4);
35	  } catch (error) {
36	    console.error("homepage_publications_preview_failed", error);
37	    return [];
38	  }
39	}
