645	function stripMarkdown(text: string): string {
646	  return text
647	    .replace(/\[(?:\d+|C:[^\]\s]+)\]/g, "the firm")
648	    .replace(/`([^`]+)`/g, "$1")
649	    .replace(/\*\*([^*]+)\*\*/g, "$1")
650	    .replace(/\*([^*]+)\*/g, "$1")
651	    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
652	    .replace(/[#>_-]+/g, " ")
653	    .replace(/\s+/g, " ")
654	    .trim();
655	}
