657	function formatTimestamp(value: string): string {
658	  const date = new Date(value);
659	  if (Number.isNaN(date.getTime())) return "Date pending";
660	
661	  return new Intl.DateTimeFormat("en-US", {
662	    day: "numeric",
663	    hour: "numeric",
664	    minute: "2-digit",
665	    month: "short",
666	    timeZone: "UTC",
667	    timeZoneName: "short",
668	    year: "numeric",
669	  }).format(date);
670	}
