672	function deriveExcerpt(text: string, limit = 300): string {
673	  const cleaned = text.replace(/\s+/g, " ").trim();
674	  if (!cleaned) return "(no preview available)";
675	  if (cleaned.length <= limit) return cleaned;
676	  const cut = cleaned.slice(0, limit);
677	  const lastSpace = cut.lastIndexOf(" ");
678	  return (lastSpace > limit * 0.65 ? cut.slice(0, lastSpace) : cut) + "…";
679	}
