      <Link
        className="mono"
        href="/about#manifesto"
        style={{
          color: "var(--amber)",
          fontSize: "0.66rem",
          letterSpacing: "0.18em",
          textDecoration: "none",
          textTransform: "uppercase",
        }}
      >
        Read the full manifesto →
      </Link>
    </section>
  );
}

function ContactLine({ email }: { email: string }) {
  return (
    <p
      style={{
        color: "var(--parchment-dim)",
        fontSize: "0.95rem",
        lineHeight: 1.6,
        margin: "0",
      }}
    >
      Reach the firm at{" "}
      <a
        href={`mailto:${email}`}
        style={{ color: "var(--amber)", textDecoration: "none" }}
      >
        {email}
      </a>
      .
    </p>
  );
}

function EmptyPublicOutput({ email }: { email: string }) {
  return (
    <section
      aria-label="No public publications yet"
      className="ascii-frame"
      data-label="PUBLIC COMMONS"
      style={{
        margin: "0 0 2rem",
        padding: "1.3rem 1.4rem",
      }}
    >
      <p
        style={{
          color: "var(--parchment)",
          fontSize: "1rem",
          lineHeight: 1.55,
          margin: 0,
        }}
      >
        The firm has not yet published anything publicly. Reach out:{" "}
        <a
          href={`mailto:${email}`}
          style={{ color: "var(--amber)", textDecoration: "none" }}
        >
          {email}
        </a>
        .
      </p>
    </section>
  );
}

function RailHeader({
  href,
  linkLabel,
  title,
  titleId,
}: {
  href?: string;
  linkLabel?: string;
  title: string;
  titleId: string;
}) {
  return (
    <div
      style={{
        alignItems: "center",
        display: "flex",
        flexWrap: "wrap",
        gap: "0.8rem",
        justifyContent: "space-between",
        marginBottom: "0.85rem",
      }}
    >
      <h2
        className="mono"
        id={titleId}
        style={{
          color: "var(--amber-dim)",
          fontSize: "0.72rem",
          letterSpacing: "0.3em",
          margin: 0,
          textTransform: "uppercase",
        }}
      >
        {title}
      </h2>
      {href && linkLabel ? (
        <Link
          className="mono"
          href={href}
          style={{
            color: "var(--amber)",
            fontSize: "0.62rem",
            letterSpacing: "0.2em",
            textDecoration: "none",
            textTransform: "uppercase",
            whiteSpace: "nowrap",
          }}
        >
          {linkLabel}
        </Link>
      ) : null}
    </div>
  );
}

function RailEmpty({ children }: { children: string }) {
  return (
    <p
      style={{
        background: "rgba(232, 225, 211, 0.035)",
        border: "1px solid rgba(232, 225, 211, 0.12)",
        color: "var(--parchment-dim)",
        fontSize: "0.95rem",
        lineHeight: 1.55,
        margin: 0,
        padding: "1rem",
      }}
    >
      {children}
    </p>
  );
}

function summarizeOpinion(opinion: PublicOpinion): string {
  if (opinion.abstention_reason) return opinion.abstention_reason;
  const body = stripMarkdown(opinion.body_markdown);
  return deriveExcerpt(body || opinion.event?.text || "", 140);
}

function stripMarkdown(text: string): string {
  return text
    .replace(/\[(?:\d+|C:[^\]\s]+)\]/g, "the firm")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\*\*([^*]+)\*\*/g, "$1")
    .replace(/\*([^*]+)\*/g, "$1")
    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    .replace(/[#>_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function formatTimestamp(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Date pending";

  return new Intl.DateTimeFormat("en-US", {
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    month: "short",
    timeZone: "UTC",
    timeZoneName: "short",
    year: "numeric",
  }).format(date);
}

function deriveExcerpt(text: string, limit = 300): string {
  const cleaned = text.replace(/\s+/g, " ").trim();
  if (!cleaned) return "(no preview available)";
  if (cleaned.length <= limit) return cleaned;
  const cut = cleaned.slice(0, limit);
  const lastSpace = cut.lastIndexOf(" ");
  return (lastSpace > limit * 0.65 ? cut.slice(0, lastSpace) : cut) + "…";
}

