353	type PublishedConclusionDbRow = {
354	  id: string;
355	  kind: string;
356	  slug: string;
357	  version: number;
358	  sourceConclusionId: string;
359	  publishedAt: Date | string;
360	  doi: string;
361	  zenodoRecordId: string;
362	  discountedConfidence: number;
363	  statedConfidence: number;
364	  calibrationDiscountReason: string;
365	  payloadJson: string;
366	};
367	
368	async function responseTargetForPost(
369	  post: PostResponseTargetInput,
370	  routeSlug: string,
371	): Promise<PublishedConclusion> {
372	  const published = await db.publishedConclusion.findFirst({
373	    where: {
374	      organizationId: post.organizationId,
375	      OR: [
376	        { id: post.id },
377	        { sourceConclusionId: post.id },
378	        { sourceConclusionId: `article:${post.id}` },
379	        { slug: post.slug ?? routeSlug },
380	      ],
381	    },
382	    orderBy: { publishedAt: "desc" },
383	    select: {
384	      id: true,
385	      kind: true,
386	      slug: true,
387	      version: true,
388	      sourceConclusionId: true,
389	      publishedAt: true,
390	      doi: true,
391	      zenodoRecordId: true,
392	      discountedConfidence: true,
393	      statedConfidence: true,
394	      calibrationDiscountReason: true,
395	      payloadJson: true,
396	    },
397	  });
398	
399	  return published
400	    ? publishedConclusionFromRow(published as PublishedConclusionDbRow)
401	    : fallbackPostResponseTarget(post, routeSlug);
402	}
403	
404	function publishedConclusionFromRow(row: PublishedConclusionDbRow): PublishedConclusion {
405	  return {
406	    id: row.id,
407	    kind: row.kind,
408	    slug: row.slug,
409	    version: row.version,
410	    sourceConclusionId: row.sourceConclusionId,
411	    publishedAt:
412	      row.publishedAt instanceof Date
413	        ? row.publishedAt.toISOString()
414	        : new Date(row.publishedAt).toISOString(),
415	    doi: row.doi,
416	    zenodoRecordId: row.zenodoRecordId,
417	    discountedConfidence: row.discountedConfidence,
418	    statedConfidence: row.statedConfidence,
419	    calibrationDiscountReason: row.calibrationDiscountReason,
420	    payload: parsePublicationPayload(row),
421	  };
422	}
423	
424	function fallbackPostResponseTarget(
425	  post: PostResponseTargetInput,
426	  routeSlug: string,
427	): PublishedConclusion {
428	  const publishedAt = post.publishedAt
429	    ? post.publishedAt.toISOString()
430	    : new Date().toISOString();
431	  const slug = post.slug ?? routeSlug;
432	
433	  return {
434	    id: post.id,
435	    kind: "POST",
436	    slug,
437	    version: 1,
438	    sourceConclusionId: `post:${post.id}`,
439	    publishedAt,
440	    doi: "",
441	    zenodoRecordId: "",
442	    discountedConfidence: 0,
443	    statedConfidence: 0,
444	    calibrationDiscountReason: "",
445	    payload: {
446	      schema: "theseus.publicConclusion.v1",
447	      conclusionText: `Respond to this post: ${post.title}`,
448	      rationale: "",
449	      topicHint: "",
450	      evidenceSummary: "",
451	      exitConditions: [],
452	      strongestObjection: { objection: "", firmAnswer: "" },
453	      openQuestionsAdjacent: [],
454	      voiceComparisons: [],
455	      methodology: {
456	        schema: "theseus.methodology.v1",
457	        reviewerNarrative: "",
458	        profiles: [],
459	      },
460	      timeline: [],
461	      whatWouldChangeOurMind: [],
462	      citations: [],
463	    },
464	  };
465	}
466	
467	/**
468	 * Format a duration in seconds as `MM:SS` or `H:MM:SS` — what a podcast
469	 * app would show next to the play button.
470	 */
471	function formatDuration(seconds: number): string {
472	  const total = Math.max(0, Math.floor(seconds));
473	  const h = Math.floor(total / 3600);
474	  const m = Math.floor((total % 3600) / 60);
475	  const s = total % 60;
476	  const mm = m.toString().padStart(2, "0");
477	  const ss = s.toString().padStart(2, "0");
478	  return h > 0 ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
479	}
480	
481	/**
482	 * Split prose into paragraphs. A "paragraph" is a block separated by
483	 * one-or-more blank lines. We also soft-split runs of plain single-line
484	 * content into paragraphs if they're long enough to warrant breaks —
485	 * but only when there are ZERO paragraph-break signals, so we don't
486	 * double-split well-formed text.
487	 */
488	function splitParagraphs(text: string): string[] {
489	  const trimmed = text.trim();
490	  if (!trimmed) return [];
491	  // Primary split: double-newline paragraph breaks (the normal case).
492	  const blocks = trimmed.split(/\n\s*\n+/);
493	  if (blocks.length > 1) {
494	    return blocks
495	      .map((b) => b.trim().replace(/\s+/g, " "))
496	      .filter(Boolean);
497	  }
498	  // Fallback: treat every 3–4 sentences as a paragraph so a long
499	  // one-line dump doesn't become an unreadable wall. 400 chars is a
500	  // reasonable paragraph in EB Garamond at 1.1rem.
501	  const SENT = /([^.!?]+[.!?]+)\s+(?=[A-Z])/g;
502	  const sentences = trimmed.replace(SENT, "$1\n").split(/\n/);
503	  const out: string[] = [];
504	  let buf = "";
505	  for (const s of sentences) {
506	    buf = buf ? buf + " " + s.trim() : s.trim();
507	    if (buf.length >= 400) {
508	      out.push(buf);
509	      buf = "";
510	    }
511	  }
512	  if (buf) out.push(buf);
513	  return out.length > 0 ? out : [trimmed];
514	}
