"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";

import type { CurrentsHealth } from "@/lib/currentsApi";
import type { PublicOpinion } from "@/lib/currentsTypes";
import {
  filterToParams,
  hasActiveMatchFilter,
  matches,
  paramsToFilter,
  type Filter,
} from "@/lib/filterMatch";
import { useLiveOpinions } from "@/lib/useLiveOpinions";

import FilterBar from "./FilterBar";
import LiveBanner from "./LiveBanner";
import OpinionCard from "./OpinionCard";
import TopicClusters from "./TopicClusters";

interface FeedClientProps {
  health: CurrentsHealth | null;
  seed: PublicOpinion[];
  detailBasePath?: string;
}

function matchFilterKey(filter: Filter): string {
  return filterToParams({ ...filter, view: "feed" }).toString();
}

function EmptyFeedMessage({ filtered }: { filtered: boolean }) {
  return (
    <div
      style={{
        background: "rgba(232, 225, 211, 0.03)",
        border: "1px solid var(--currents-border)",
        borderLeft: "4px solid var(--currents-stance-abstained)",
        borderRadius: "6px",
        color: "var(--currents-parchment-dim)",
        padding: "1rem",
      }}
    >
      {filtered
        ? "No opinions match these filters."
        : "No opinions yet. The firm abstains when its knowledge base does not support a position."}
    </div>
  );
}

function DisabledBanner({ health }: { health: CurrentsHealth | null }) {
  if (!health || health.disabled_reasons.length === 0) return null;
  const reasons = health.disabled_reasons.join(", ");
  return (
    <div
      role="status"
      style={{
        background: "rgba(172, 54, 37, 0.13)",
        border: "1px solid rgba(255, 111, 82, 0.55)",
        borderLeft: "4px solid var(--currents-stance-disagrees)",
        borderRadius: "6px",
        color: "var(--currents-parchment)",
        fontFamily: "'IBM Plex Mono', monospace",
        fontSize: "0.78rem",
        lineHeight: 1.55,
        marginBottom: "1rem",
        padding: "0.75rem 0.9rem",
      }}
    >
      Currents disabled — set X_BEARER_TOKEN. If discovery is disabled, also
      set CURRENTS_X_CURATED_ACCOUNTS or CURRENTS_X_SEARCH_QUERIES.
      <span style={{ color: "var(--currents-parchment-dim)" }}>
        {" "}
        Reason: {reasons}.
      </span>
    </div>
  );
}

export default function FeedClient({
  health,
  seed,
  detailBasePath = "/currents",
}: FeedClientProps) {
  const seedIds = useRef(new Set(seed.map((opinion) => opinion.id)));
  const seenOpinionIds = useRef(new Set(seed.map((opinion) => opinion.id)));
  const activeFilterKey = useRef<string | null>(null);
  const [otherFilterCount, setOtherFilterCount] = useState(0);
  const pathname = usePathname() || "/currents";
  const router = useRouter();
  const searchParams = useSearchParams();
  const searchParamString = searchParams.toString();
  const { opinions, connected } = useLiveOpinions(seed);
  const filter = useMemo(
    () => paramsToFilter(searchParamString),
    [searchParamString],
  );
  const filteredOpinions = useMemo(
    () => opinions.filter((opinion) => matches(opinion, filter)),
    [filter, opinions],
  );
  const activeCriteria = hasActiveMatchFilter(filter);

  useEffect(() => {
    const nextFilterKey = matchFilterKey(filter);

    if (activeFilterKey.current !== nextFilterKey) {
      activeFilterKey.current = nextFilterKey;
      seenOpinionIds.current = new Set(opinions.map((opinion) => opinion.id));
      setOtherFilterCount(0);
      return;
    }

    if (!activeCriteria) {
      seenOpinionIds.current = new Set(opinions.map((opinion) => opinion.id));
      setOtherFilterCount(0);
      return;
    }

    let hiddenArrivalCount = 0;

    for (const opinion of opinions) {
      if (seenOpinionIds.current.has(opinion.id)) continue;
      seenOpinionIds.current.add(opinion.id);
      if (!matches(opinion, filter)) hiddenArrivalCount += 1;
    }

    if (hiddenArrivalCount) {
      setOtherFilterCount((count) => count + hiddenArrivalCount);
    }
  }, [activeCriteria, filter, opinions]);

  const clearFilters = () => {
    setOtherFilterCount(0);
    router.replace(pathname, { scroll: false });
  };

  return (
    <section aria-label="Current-events opinions">
      <DisabledBanner health={health} />
      <LiveBanner connected={connected} />
      <FilterBar opinions={opinions} />

      {otherFilterCount ? (
        <button
          onClick={clearFilters}
          style={{
            background: "rgba(212, 160, 23, 0.12)",
            border: "1px solid var(--currents-gold)",
            borderRadius: "6px",
            color: "var(--currents-gold)",
            cursor: "pointer",
            fontFamily: "'IBM Plex Mono', monospace",
            fontSize: "0.78rem",
            letterSpacing: "0.03em",
            marginBottom: "1rem",
            padding: "0.65rem 0.8rem",
            width: "100%",
          }}
          type="button"
        >
          {otherFilterCount} new items match other filters
        </button>
      ) : null}

      {filteredOpinions.length && filter.view === "clusters" ? (
        <TopicClusters
          basePath={pathname}
          detailBasePath={detailBasePath}
          filter={filter}
          opinions={filteredOpinions}
        />
      ) : filteredOpinions.length ? (
        <div
          aria-live="polite"
          style={{
            display: "grid",
            gap: "0.9rem",
          }}
        >
          {filteredOpinions.map((opinion) => (
            <OpinionCard
              key={opinion.id}
              detailBasePath={detailBasePath}
              opinion={opinion}
              className={seedIds.current.has(opinion.id) ? undefined : "currents-fade-in"}
            />
          ))}
        </div>
      ) : (
        <EmptyFeedMessage filtered={opinions.length > 0} />
      )}
    </section>
  );
}

import type { CSSProperties, ReactNode } from "react";

import PublicHeader from "@/components/PublicHeader";
import { getFounder } from "@/lib/auth";

export const metadata = { title: "Current events — Theseus" };

const containerStyle: CSSProperties = {
  maxWidth: "1040px",
  margin: "0 auto",
  paddingLeft: "1.25rem",
  paddingRight: "1.25rem",
};

export default async function CurrentsLayout({ children }: { children: ReactNode }) {
  const founder = await getFounder();

  return (
    <div
      style={{
        background: "var(--currents-bg)",
        minHeight: "100vh",
        color: "var(--currents-parchment)",
        paddingBottom: "4rem",
      }}
    >
      <PublicHeader authed={Boolean(founder)} />
      <header
        style={{
          padding: "2rem 0 1rem",
          borderBottom: "1px solid var(--currents-border)",
        }}
      >
        <div style={containerStyle}>
          <div
            style={{
              fontSize: "0.75rem",
              letterSpacing: "0.16em",
              textTransform: "uppercase",
              color: "var(--currents-amber)",
            }}
          >
            Theseus · live
          </div>
          <h1
            style={{
              fontFamily: "'EB Garamond', serif",
              fontSize: "1.85rem",
              margin: "0.4rem 0 0.2rem",
            }}
          >
            X posts, firm opinion.
          </h1>
          <p
            style={{
              color: "var(--currents-parchment-dim)",
              maxWidth: "60ch",
              margin: 0,
              fontSize: "0.95rem",
            }}
          >
            The firm watches live public signals, then publishes what its
            collective reasoning currently believes. When the firm cannot reach
            a responsible view, it abstains.
          </p>
        </div>
      </header>
      <div style={{ ...containerStyle, paddingTop: "1.6rem" }}>
        {children}
        <footer
          style={{
            marginTop: "3rem",
            paddingTop: "1.1rem",
            borderTop: "1px solid var(--currents-border)",
            fontSize: "0.78rem",
            lineHeight: 1.6,
            color: "var(--currents-parchment-dim)",
            fontStyle: "italic",
          }}
        >
          <p style={{ margin: 0, maxWidth: "52em" }}>
            Opinions on this page are generated from the firm's Noosphere of
            conclusions and claims. They are not legal or financial advice, and
            not an exhaustive survey of the firm's thinking. The firm abstains
            when its modeled judgment is not strong enough to publish; an
            abstention is not agreement with the observed post. Follow-up answers
            ask the Noosphere anew on each question rather than answering from
            memory.
          </p>
        </footer>
      </div>
    </div>
  );
}

import type { CSSProperties, ReactNode } from "react";

import PublicHeader from "@/components/PublicHeader";
import { getFounder } from "@/lib/auth";

export const metadata = { title: "Forecasts — Theseus" };

const containerStyle: CSSProperties = {
  maxWidth: "1120px",
  margin: "0 auto",
  paddingLeft: "1.25rem",
  paddingRight: "1.25rem",
};

export default async function ForecastsLayout({ children }: { children: ReactNode }) {
  const founder = await getFounder();

  return (
    <div
      style={{
        background: "var(--forecasts-bg)",
        color: "var(--forecasts-parchment)",
        minHeight: "100vh",
        paddingBottom: "4rem",
      }}
    >
      <PublicHeader authed={Boolean(founder)} />
      <header
        style={{
          borderBottom: "1px solid var(--forecasts-border)",
          padding: "2rem 0 1rem",
        }}
      >
        <div style={containerStyle}>
          <div
            style={{
              color: "var(--forecasts-cool-gold)",
              fontSize: "0.75rem",
              letterSpacing: "0.16em",
              textTransform: "uppercase",
            }}
          >
            Theseus · forecasts
          </div>
          <h1
            style={{
              fontFamily: "'EB Garamond', serif",
              fontSize: "1.85rem",
              margin: "0.4rem 0 0.2rem",
            }}
          >
            Macro predictions, source-grounded.
          </h1>
          <p
            style={{
              color: "var(--forecasts-parchment-dim)",
              fontSize: "0.95rem",
              margin: 0,
              maxWidth: "62ch",
            }}
          >
            Forecasts are published only when the model can cite at least three
            verifiable sources. Probabilities are compared against the market's
            implied YES price, then scored when the market resolves.
          </p>
        </div>
      </header>
      <div style={{ ...containerStyle, paddingTop: "1.6rem" }}>
        {children}
        <footer
          style={{
            borderTop: "1px solid var(--forecasts-border)",
            color: "var(--forecasts-parchment-dim)",
            fontSize: "0.78rem",
            fontStyle: "italic",
            lineHeight: 1.6,
            marginTop: "3rem",
            paddingTop: "1.1rem",
          }}
        >
          <p style={{ margin: 0, maxWidth: "56em" }}>
            Forecasts are generated from the firm's published Noosphere and market
            data. They are not financial advice. Paper bets are shown publicly;
            live operator activity is separated from this reader-facing stream.
          </p>
        </footer>
      </div>
    </div>
  );
}

