  const style = verdictPill(verdict.relation_holds);
  const overridden = Boolean(verdict.overridden_by && verdict.override_reason);
  const summary = verdictSummary(verdict);
  return (
    <div
      data-testid="citation-verdict"
      data-verdict={verdict.relation_holds}
      style={{ marginTop: "0.4rem" }}
      title={summary}
    >
      <span
        aria-label={`Citation verdict: ${style.label}`}
        data-testid="citation-verdict-pill"
        style={{
          background: style.bg,
          border: "1px solid rgba(0,0,0,0.35)",
          borderRadius: "999px",
          color: style.fg,
          display: "inline-block",
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: "0.65rem",
          letterSpacing: "0.1em",
          padding: "0.15rem 0.55rem",
          textTransform: "uppercase",
        }}
      >
        {style.label}
      </span>
      {overridden ? (
        <span
          style={{
            color: "var(--currents-muted)",
            fontSize: "0.7rem",
            marginLeft: "0.5rem",
          }}
        >
          founder override
        </span>
      ) : null}
      <p
        style={{
          color: "var(--currents-parchment-dim)",
          fontSize: "0.72rem",
          lineHeight: 1.4,
          margin: "0.35rem 0 0",
        }}
      >
        {summary}
      </p>
    </div>
  );
}

interface CredibilityStripProps {
  credibility: SourceCredibilityPayload;
}

function CredibilityStrip({ credibility }: CredibilityStripProps) {
  const score = Math.max(0, Math.min(100, credibility.score_100));
  const fill = scoreBandColor(score);
  const bandLabel = scoreBandLabel(score);
  const summary = summaryLine(credibility);
  const tooltip = credibility.confident
    ? summary
    : `${summary} — ${unconfidentCaveat(credibility)}`;

  return (
    <div
      data-testid="source-credibility"
      style={{
        borderTop: "1px solid var(--currents-border)",
        marginTop: "0.7rem",
        paddingTop: "0.55rem",
      }}
      title={tooltip}
    >
      <div
        style={{
          alignItems: "baseline",
          color: "var(--currents-muted)",
          display: "flex",
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: "0.65rem",
          justifyContent: "space-between",
          letterSpacing: "0.1em",
          textTransform: "uppercase",
        }}
      >
        <span>Source credibility</span>
        <span style={{ color: "var(--currents-parchment-dim)" }}>
          {sourceTypeLabel(credibility.source_type)}
        </span>
      </div>
      <div
        aria-label={
          credibility.confident
            ? `Source credibility ${score} of 100 (${bandLabel})`
            : `Source credibility unsettled — ${credibility.n_updates} of ${credibility.min_updates_for_confidence} updates`
        }
        role="img"
        style={{
          background: "rgba(255,255,255,0.06)",
          borderRadius: "3px",
          height: "8px",
          marginTop: "0.35rem",
          overflow: "hidden",
          position: "relative",
          width: "100%",
        }}
      >
        <div
          data-testid="source-credibility-fill"
          style={{
            background: credibility.confident ? fill : "rgba(255,255,255,0.18)",
            height: "100%",
            transition: "width 200ms ease",
            width: `${score}%`,
          }}
        />
      </div>
      <div
        style={{
          color: "var(--currents-parchment-dim)",
          display: "flex",
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: "0.7rem",
          justifyContent: "space-between",
          marginTop: "0.3rem",
        }}
      >
        <span data-testid="source-credibility-score">
          {credibility.confident
            ? `${score.toFixed(score % 1 === 0 ? 0 : 1)} / 100`
            : `n=${credibility.n_updates} updates`}
        </span>
        <span style={{ color: "var(--currents-muted)" }}>{summary}</span>
      </div>
      {!credibility.confident ? (
        <p
          style={{
            color: "var(--currents-muted)",
            fontSize: "0.72rem",
            lineHeight: 1.4,
            margin: "0.35rem 0 0",
          }}
        >
          {unconfidentCaveat(credibility)}
        </p>
      ) : null}
    </div>
  );
}

export default function CitationPopover({
  open,
  onClose,
  anchorRef,
  citation,
  conclusionText,
  publicUrl,
  id,
}: CitationPopoverProps) {
  const rawId = useId();
  const popoverId = id ?? `citation-popover-${rawId.replace(/:/g, "")}`;
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const [position, setPosition] = useState<PopoverPosition | null>(null);
  const href = canExposePublicUrl(citation, publicUrl) ? safeHref(publicUrl) : null;
  const text =
    conclusionText.trim() ||
    citation.quoted_span.trim() ||
    "Firm conclusion text unavailable.";

  const updatePosition = useCallback(() => {
    const anchor = anchorRef.current;
    if (!anchor) {
      onClose();
      return;
    }
    if (anchorIsOutsideViewport(anchor)) {
      onClose();
      return;
    }
    setPosition(positionFor(anchor, dialogRef.current));
  }, [anchorRef, onClose]);

  useEffect(() => {
    if (!open) return;
    updatePosition();
    window.addEventListener("resize", updatePosition);
    window.addEventListener("scroll", updatePosition, true);
    return () => {
      window.removeEventListener("resize", updatePosition);
      window.removeEventListener("scroll", updatePosition, true);
    };
  }, [open, updatePosition]);

  useEffect(() => {
    if (!open) return;

    const handlePointerDown = (event: MouseEvent | TouchEvent) => {
      const target = event.target as Node | null;
      if (!target) return;
      if (dialogRef.current?.contains(target)) return;
      if (anchorRef.current?.contains(target)) return;
      onClose();
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onClose();
      }
    };

    document.addEventListener("mousedown", handlePointerDown);
    document.addEventListener("touchstart", handlePointerDown);
    document.addEventListener("keydown", handleKeyDown);
    return () => {
      document.removeEventListener("mousedown", handlePointerDown);
      document.removeEventListener("touchstart", handlePointerDown);
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, [anchorRef, onClose, open]);

  useEffect(() => {
    if (!open) return;
    const previousFocus = document.activeElement;
    const frame = window.requestAnimationFrame(() => {
      const dialog = dialogRef.current;
      if (!dialog) return;
      const [first] = focusableElements(dialog);
      (first ?? dialog).focus();
    });

    return () => {
      window.cancelAnimationFrame(frame);
      if (isHTMLElement(previousFocus)) previousFocus.focus();
    };
  }, [open]);

  const trapFocus = (event: ReactKeyboardEvent<HTMLDivElement>) => {
    if (event.key !== "Tab") return;
    const dialog = dialogRef.current;
    if (!dialog) return;
    const focusable = focusableElements(dialog);
    if (!focusable.length) {
      event.preventDefault();
      dialog.focus();
      return;
    }

    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    const active = document.activeElement;
    if (event.shiftKey && active === first) {
      event.preventDefault();
      last.focus();
    } else if (!event.shiftKey && active === last) {
      event.preventDefault();
      first.focus();
    }
  };

  if (!open || typeof document === "undefined") return null;

  const standing = normalizedStanding(citation);
  const standingMeta = standing === "active" ? null : STANDING_STYLE[standing];
  const reason = standingReason(citation);
  const credibility = normalizeCredibilityPayload(
    citation.source_credibility ?? citation.sourceCredibility ?? null,
  );
  const verdict = normalizeVerdictPayload(
    citation.citation_verdict ?? citation.citationVerdict ?? null,
  );

  return createPortal(
    <div
      aria-modal="false"
      id={popoverId}
      onKeyDown={trapFocus}
      ref={dialogRef}
      role="dialog"
      style={{
        ...shellStyle,
        left: `${position?.left ?? MARGIN}px`,
        opacity: position ? 1 : 0,
        top: `${position?.top ?? MARGIN}px`,
      }}
      tabIndex={-1}
    >
      <div
        style={{
          alignItems: "start",
          display: "flex",
          gap: "0.75rem",
          justifyContent: "space-between",
        }}
      >
        <div>
          <div style={captionStyle}>{citationKind(citation)}</div>
          <h2 style={titleStyle}>{citationTitle(citation)}</h2>
          {standingMeta ? (
            <div style={{ marginTop: "0.4rem" }}>
              <span
                aria-label={`Source standing: ${standingMeta.label}`}
                data-testid="source-standing-pill"
                style={{
                  background: standingMeta.bg,
                  border: "1px solid rgba(0,0,0,0.35)",
                  borderRadius: "999px",
                  color: standingMeta.fg,
                  display: "inline-block",
                  fontFamily: "'IBM Plex Mono', monospace",
                  fontSize: "0.65rem",
                  letterSpacing: "0.1em",
                  padding: "0.15rem 0.55rem",
                  textTransform: "uppercase",
                }}
              >
                {standingMeta.label}
              </span>
              {reason ? (
                <span
                  style={{
                    color: "var(--currents-muted)",
                    fontSize: "0.72rem",
                    marginLeft: "0.55rem",
                  }}
                >
                  {reason}
                </span>
              ) : null}
              {standing === "retracted" || standing === "corrected" ? (
                <a
                  href="/methodology#source-standing"
                  style={{
                    color: "var(--currents-gold)",
                    display: "inline-block",
                    fontSize: "0.72rem",
                    marginLeft: "0.55rem",
                    textDecoration: "underline",
                  }}
                >
                  this source has been retracted →
                </a>
              ) : null}
            </div>
          ) : null}
          {verdict ? <CitationVerdictPill verdict={verdict} /> : null}
        </div>
        <button
          aria-label="Close citation"
          onClick={onClose}
          style={{
            background: "transparent",
            border: "1px solid var(--currents-border)",
            borderRadius: "4px",
            color: "var(--currents-parchment-dim)",
            cursor: "pointer",
            fontSize: "0.8rem",
            lineHeight: 1,
            padding: "0.25rem 0.35rem",
          }}
          type="button"
        >
          ×
        </button>
      </div>

      {credibility ? (
        <CredibilityStrip credibility={credibility} />
      ) : null}

      <div style={bodyStyle}>{renderSafeMarkdown(text)}</div>

      {href ? (
        <a href={href} rel="noopener nofollow ugc" style={linkStyle} target="_blank">
          Open the public conclusion →
        </a>
      ) : (
        <p style={privateNoteStyle}>
          Source recorded by the firm; not publicly available.
        </p>
      )}
    </div>,
    document.body,
  );
}

"use client";

import { type CSSProperties, useEffect, useState } from "react";

import {
  markFirstUseTipShown,
  readToggle,
  shouldShowFirstUseTip,
  writeToggle,
  type SentenceProvenanceReport,
} from "@/lib/sentenceProvenance";

import AnswerMarkdown from "./AnswerMarkdown";
import ProvenanceGutter from "./ProvenanceGutter";

interface ProvenanceArticleProps {
  bodyMarkdown: string;
  report: SentenceProvenanceReport;
}

const layoutStyle: CSSProperties = {
  display: "grid",
  gap: "0.85rem",
  gridTemplateColumns: "auto 1fr",
};

const toolbarStyle: CSSProperties = {
  alignItems: "center",
  display: "flex",
  gap: "0.55rem",
  marginBottom: "0.55rem",
};

const toggleButtonStyle: CSSProperties = {
  background: "transparent",
  border: "1px solid var(--currents-border, #3a3024)",
  borderRadius: "999px",
  color: "var(--currents-parchment-dim, #d8c9ad)",
  cursor: "pointer",
  fontFamily: "'IBM Plex Mono', monospace",
  fontSize: "0.72rem",
  letterSpacing: "0.06em",
  padding: "0.25rem 0.7rem",
};

const tipStyle: CSSProperties = {
  background: "var(--currents-bg-elevated, #1d1a16)",
  border: "1px solid var(--currents-amber-deep, #6b4f23)",
  borderRadius: "4px",
  color: "var(--currents-parchment-dim, #d8c9ad)",
  fontSize: "0.78rem",
  lineHeight: 1.45,
  marginBottom: "0.6rem",
  padding: "0.5rem 0.7rem",
};

/**
 * Article-body wrapper that renders the markdown body alongside the
 * provenance gutter. Keeps the toggle state local-only so the parent
 * (a server component) need not be turned into a client component.
 */
export default function ProvenanceArticle({
  bodyMarkdown,
  report,
}: ProvenanceArticleProps) {
  const [visible, setVisible] = useState<boolean>(false);
  const [showTip, setShowTip] = useState<boolean>(false);

  useEffect(() => {
    setVisible(readToggle());
    setShowTip(shouldShowFirstUseTip());
  }, []);

  const onToggle = () => {
    setVisible((prev) => {
      const next = !prev;
      writeToggle(next);
      if (next && showTip) {
        markFirstUseTipShown();
        setShowTip(false);
      }
      return next;
    });
  };

  return (
    <div data-testid="provenance-article">
      <div role="toolbar" style={toolbarStyle}>
        <button
          aria-pressed={visible}
          data-testid="provenance-toggle"
          onClick={onToggle}
          style={{
            ...toggleButtonStyle,
            background: visible ? "rgba(214, 156, 63, 0.18)" : "transparent",
            color: visible
              ? "var(--currents-amber, #d69c3f)"
              : "var(--currents-parchment-dim, #d8c9ad)",
          }}
          type="button"
        >
          {visible ? "Hide provenance" : "Show provenance"}
        </button>
        <span
          aria-hidden="true"
          style={{
            color: "var(--currents-muted, #948374)",
            fontSize: "0.72rem",
          }}
        >
          gutter shades sentences by evidence weight
        </span>
      </div>

      {visible && showTip ? (
        <div data-testid="provenance-tip" role="note" style={tipStyle}>
          The gutter shades each sentence by the strength of its supporting evidence.
          Click a faintly-shaded cell to see which sources carry that sentence.
        </div>
      ) : null}

      <div style={layoutStyle}>
        <ProvenanceGutter
          bodyMarkdown={bodyMarkdown}
          report={report}
          visible={visible}
        />
        <div className="public-article-body">
          <AnswerMarkdown>{bodyMarkdown}</AnswerMarkdown>
        </div>
      </div>
    </div>
  );
}

import Link from "next/link";
import type { ReactNode } from "react";

import type { PublishedConclusion, PublicResponse } from "@/lib/conclusionsRead";
import type { MqsRecord } from "@/lib/methodologyProfiles";
import {
  fallbackReport,
  reportMatchesBody,
  type SentenceProvenanceReport,
} from "@/lib/sentenceProvenance";

import AnswerMarkdown from "./AnswerMarkdown";
import MqsPill from "./MqsPill";
import ProvenanceArticle from "./ProvenanceArticle";

function clamp01(n: number) {
  if (Number.isNaN(n)) return 0;
  return Math.min(1, Math.max(0, n));
}

function percent(n: number) {
  return `${(clamp01(n) * 100).toFixed(0)}%`;
}

function formatPatternType(value: string) {
  const formatted = value.replace(/[_-]+/g, " ").trim();
  return formatted || "method profile";
}

function citationKindLabel(value: string) {
  const normalized = value.replace(/[_-]+/g, " ").trim().toLowerCase();
  if (normalized === "event opinion") return "opinion";
  if (normalized === "current event") return "event";
  if (normalized === "forecast postmortem") return "forecast";
  return normalized || "source";
}

function isExternalHref(href: string) {
  return /^https?:\/\//i.test(href);
}

function MethodList({ label, items }: { label: string; items: string[] }) {
  if (!items.length) return null;

  return (
    <div className="public-method-list-group">
      <h4 className="mono">{label}</h4>
      <ul className="public-method-list">
        {items.map((item, index) => (
          <li key={`${label}:${index}`}>{item}</li>
        ))}
      </ul>
    </div>
  );
}

export default function ConclusionView({
  row,
  responses,
  topSlot,
  bottomSlot,
  mqs,
  provenanceReport,
}: {
  row: PublishedConclusion;
  allVersions: PublishedConclusion[];
  responses: PublicResponse[];
  topSlot?: ReactNode;
  bottomSlot?: ReactNode;
  /**
   * Public MQS pill. Only rendered when an MQS exists AND is fresh
   * (scored at-or-after the conclusion's last edit). Freshness/publish
   * gating happens upstream — passing `null` hides the pill.
   */
  mqs?: MqsRecord | null;
  /**
   * Public-projected sentence-provenance report assembled at publish
   * time by `noosphere.cascade.sentence_provenance`. Optional — when
   * absent (legacy publications), the article falls back to a
   * conservative client-side report built from the citation manifest.
   */
  provenanceReport?: SentenceProvenanceReport | null;
}) {
  const p = row.payload;
  const article = p.article;
  const isArticle = row.kind === "ARTICLE" && Boolean(article?.bodyMarkdown);
  const articleReport: SentenceProvenanceReport | null =
    isArticle && article
      ? reportMatchesBody(provenanceReport, article.bodyMarkdown)
        ? provenanceReport
        : fallbackReport(row.id, article.bodyMarkdown, article.citations)
      : null;
  const methodologyNarrative = p.methodology.reviewerNarrative.trim();
  const methodologyProfiles = p.methodology.profiles;
  const hasMethodology = Boolean(methodologyNarrative || methodologyProfiles.length);

  return (
    <main className="public-container">
      {topSlot}

      <p className="public-muted public-kicker">
        <span>
          {isArticle ? "ARTICLE" : `v${row.version}`} · published {row.publishedAt.slice(0, 10)}
        </span>
        {row.doi ? (
          <>
            {" "}
            ·{" "}
            <a href={`https://doi.org/${encodeURIComponent(row.doi)}`} rel="noreferrer">
              DOI: {row.doi}
            </a>
          </>
        ) : null}
      </p>

      <h1 className="public-title">{p.conclusionText}</h1>

      {mqs ? (
        <p className="public-muted public-kicker" style={{ marginTop: "-0.5rem" }}>
          <MqsPill mqs={mqs} />
        </p>
      ) : null}

      {!isArticle ? (
        <section className="public-card">
          <h2>Confidence</h2>
          <p className="public-muted">
            Headline (calibration-discounted): <strong>{percent(row.discountedConfidence)}</strong>
            <span className="public-inline-stat">
              Stated / model confidence (context): <strong>{percent(row.statedConfidence)}</strong>
            </span>
          </p>
          {row.calibrationDiscountReason ? <p>{row.calibrationDiscountReason}</p> : null}
        </section>
      ) : null}

      <section className="public-section">
        <h2>{isArticle ? "The firm's perspective" : "Why the firm believes this"}</h2>
        {isArticle && article && articleReport ? (
          <ProvenanceArticle
            bodyMarkdown={article.bodyMarkdown}
            report={articleReport}
          />
        ) : isArticle && article ? (
          <div className="public-article-body">
            <AnswerMarkdown>{article.bodyMarkdown}</AnswerMarkdown>
          </div>
        ) : (
          <p>{p.evidenceSummary || p.rationale}</p>
        )}
      </section>

      {isArticle && article ? <ArticleSourceList citations={article.citations} /> : null}

      {hasMethodology ? (
        <section aria-labelledby="conclusion-methodology-title" className="public-section public-methodology-section">
          <div className="public-section-heading">
            <h2 id="conclusion-methodology-title">Method used to reach this view</h2>
            <Link className="public-section-link mono" href="/methodology">
              Methodology orientation
            </Link>
          </div>
          <p className="public-card public-method-note" role="note">
            This is a public, reviewer-approved abstraction of the reasoning process. It is not a raw transcript, source
            excerpt, or claim that the conclusion automatically transfers to another domain.
          </p>
          {methodologyNarrative ? <p className="public-method-narrative">{methodologyNarrative}</p> : null}
          {methodologyProfiles.length ? (
            <div className="public-method-grid" role="list">
              {methodologyProfiles.map((profile, index) => {
                const headingId = `method-profile-${index}`;
                return (
                  <article
                    aria-labelledby={headingId}
                    className="public-card public-method-card"
                    key={`${profile.patternType}:${profile.title}`}
                    role="listitem"
                  >
                    <div className="public-method-meta mono">
                      <span>{formatPatternType(profile.patternType)}</span>
                      <span>{percent(profile.confidence)}</span>
                    </div>
                    <h3 id={headingId}>{profile.title}</h3>
                    <p className="public-method-summary">{profile.summary}</p>
                    <MethodList label="Reasoning moves" items={profile.reasoningMoves} />
                    <MethodList label="Working assumptions" items={profile.assumptions} />
                    <MethodList label="Potential transfer targets" items={profile.transferTargets} />
                    <MethodList label="Failure modes" items={profile.failureModes} />
                  </article>
                );
              })}
            </div>
          ) : (
            <p className="public-muted">No reusable method profile was attached to this publication.</p>
          )}
        </section>
      ) : null}

      {p.openQuestionsAdjacent?.length ? (
        <section className="public-section">
          <h2>Adjacent open questions</h2>
          <ul>
            {p.openQuestionsAdjacent.map((x) => (
              <li key={x}>{x}</li>
            ))}
          </ul>
        </section>
      ) : null}

      {p.voiceComparisons?.length ? (
        <section className="public-section">
          <h2>Tracked voices (comparison)</h2>
          <ul>
            {p.voiceComparisons.map((v) => (
              <li key={`${v.voice}:${v.stance}`}>
                <strong>{v.voice}:</strong> {v.stance}
              </li>
            ))}
          </ul>
        </section>
      ) : null}

      {responses.length ? (
        <section className="public-section">
          <h2>Public responses</h2>
          <ul className="public-response-list">
            {responses.map((r) => (
              <li key={r.id} className="public-card">
                <div className="public-muted mono">
                  {r.kind} · {r.status}
                  {r.pseudonymous ? " · pseudonymous (email verified)" : ""} · {r.createdAt.slice(0, 10)}
                </div>
                <p>{r.body}</p>
                {r.citationUrl ? (
                  <p className="public-muted">
                    Citation:{" "}
                    <a href={r.citationUrl} rel="noreferrer">
                      {r.citationUrl}
                    </a>
                  </p>
                ) : null}
              </li>
            ))}
          </ul>
        </section>
      ) : null}

      {bottomSlot}
    </main>
  );
}

function ArticleSourceList({
  citations,
}: {
  citations: NonNullable<PublishedConclusion["payload"]["article"]>["citations"];
}) {
  if (!citations.length) return null;

  return (
    <section aria-labelledby="article-sources-title" className="public-section">
      <h2 id="article-sources-title">Sources</h2>
      <ol className="firm-source-list">
        {citations.map((citation) => {
          const sourceText = citation.sourceConclusionText?.trim() || null;
          const href = sourceText ? citation.publicUrl : null;
          const sourceKind = citationKindLabel(citation.sourceKind);
          return (
            <li className="firm-source-row" key={`${citation.label}:${citation.sourceKind}:${citation.sourceId}`}>
              {sourceText ? (
                <>
                  {href ? (
                    <Link
                      href={href}
                      rel={isExternalHref(href) ? "noreferrer" : undefined}
                      target={isExternalHref(href) ? "_blank" : undefined}
                    >
                      {sourceText}
                    </Link>
                  ) : (
                    <span>{sourceText}</span>
                  )}
                  <small aria-hidden="true" className="mono">
                    {sourceKind}
                  </small>
                </>
              ) : (
                <span className="public-muted">Internal source recorded by the firm</span>
              )}
            </li>
          );
        })}
      </ol>
    </section>
  );
}

