96	function installDom() {
97	  const documentListeners = new Map<string, Listener[]>();
98	  const windowListeners = new Map<string, Listener[]>();
99	  const addListener = (map: Map<string, Listener[]>) => (type: string, listener: Listener) => {
100	    map.set(type, [...(map.get(type) ?? []), listener]);
101	  };
102	  const removeListener = (map: Map<string, Listener[]>) => (type: string, listener: Listener) => {
103	    map.set(
104	      type,
105	      (map.get(type) ?? []).filter((item) => item !== listener),
106	    );
107	  };
108	
109	  vi.stubGlobal("document", {
110	    activeElement: null,
111	    addEventListener: addListener(documentListeners),
112	    body: fakeElement("body"),
113	    documentElement: { clientHeight: 768, clientWidth: 1024 },
114	    removeEventListener: removeListener(documentListeners),
115	  });
116	  vi.stubGlobal("window", {
117	    addEventListener: addListener(windowListeners),
118	    cancelAnimationFrame: vi.fn(),
119	    innerHeight: 768,
120	    innerWidth: 1024,
121	    removeEventListener: removeListener(windowListeners),
122	    requestAnimationFrame: (callback: FrameRequestCallback) => {
